local LBlockMiniGameBaseCtrl = LXImport(".LBlockMiniGameBaseCtrl")

---@class LBlockMiniGameObjsCtrl:LBlockMiniGameBaseCtrl
local LBlockMiniGameObjsCtrl = LxClass("LBlockMiniGameObjsCtrl", LBlockMiniGameBaseCtrl)
-----------------------------------------------------------------
local table                  = table
local pairs                  = pairs
local ipairs                 = ipairs
local string                 = string
local math                   = math
local tonumber               = tonumber

local LBlockMiniGameConst    = LBlockMiniGameConst
local LBlockMiniGameObj      = LXImport("..Object.LBlockMiniGameObj")

-----------------------------------------------------------------
function LBlockMiniGameObjsCtrl:LBlockMiniGameObjsCtrl()
    -- gModelBlockMiniGame
    self._model = gModelBlockMiniGame

    -- 我方对象列表
    self._selfObjs = {}

    -- 敌方对象列表
    self._enemyObjs = {}

    -- 敌方怪物生成设置
    self._enemyMonsterSetting = {}

    -- 是否开始生产敌方怪物
    self._isStartSpawnEnemyMonster = false

    self:InitEvent()
end

-- 销毁
function LBlockMiniGameObjsCtrl:OnDestroy()
    for i, obj in pairs(self._selfObjs) do
        obj:Destroy()
    end
    self._selfObjs = {}

    for i, obj in pairs(self._enemyObjs) do
        obj:Destroy()
    end
    self._enemyObjs = {}
end

-- 销毁对象
function LBlockMiniGameObjsCtrl:DestroyObj(obj)
    local key = obj:GetKey()
    if self._selfObjs[key] then
        self._selfObjs[key]:Destroy()
        self._selfObjs[key] = nil
    end
    if self._enemyObjs[key] then
        self._enemyObjs[key]:Destroy()
        self._enemyObjs[key] = nil
    end
end

-- 重新开始
function LBlockMiniGameObjsCtrl:OnReStart()
    for i, obj in pairs(self._selfObjs) do
        obj:Destroy()
    end
    self._selfObjs = {}

    for i, obj in pairs(self._enemyObjs) do
        obj:Destroy()
    end
    self._enemyObjs = {}

    self:EventRemoveAll()
    self:LBlockMiniGameObjsCtrl()
end

-- 初始化事件
function LBlockMiniGameObjsCtrl:InitEvent()
    self:EventRecv(EventNames.BLOCKMINIGAME_PAUSE, function() self:OnPauseGame() end)
    self:EventRecv(EventNames.BLOCKMINIGAME_RESUME, function() self:OnResumeGame() end)
    self:EventRecv(EventNames.BLOCKMINIGAME_OVER, function() self:OnGameOver() end)
end

-- 初始化敌方怪物生成设置
function LBlockMiniGameObjsCtrl:InitEnemyMonsterSetting()
    self._enemyMonsterSetting = {}
    local levRef = self:GetMap():GetRef()
    local tab = string.split(levRef.monsterRate, ",") or {}
    for _, v in ipairs(tab) do
        local tab2 = string.split(v, "=")
        local monsterRefId = tonumber(tab2[1])
        local time = tonumber(tab2[3]) / 1000 -- 秒
        local initTime = tonumber(tab2[2]) -- 秒

        self._enemyMonsterSetting[monsterRefId] = {monsterRefId = monsterRefId,startTime = 0, initTime = initTime, totalTime = time, leftTime = 0 }
    end
end

-- 开始游戏
function LBlockMiniGameObjsCtrl:StartGame()
    self:InitEnemyMonsterSetting()
    self:CreateTower()
end

-- 创建我方与敌方塔
function LBlockMiniGameObjsCtrl:CreateTower()
    local selfTower  = LBlockMiniGameObj:New(self)
    local enemyTower = LBlockMiniGameObj:New(self)
    local levRef     = self:GetMap():GetRef()
    local parent     = self:GetMap():GetObjRootTrans()
    local Side       = LBlockMiniGameConst.Side
    local ObjType    = LBlockMiniGameConst.ObjType

    selfTower:Init(parent, levRef.pagodaPlayer, Side.Self, ObjType.Tower)
    enemyTower:Init(parent, levRef.pagodaBoss, Side.Enemy, ObjType.Tower)

    self._selfObjs[selfTower:GetKey()] = selfTower
    self._enemyObjs[enemyTower:GetKey()] = enemyTower

    self._isStartSpawnEnemyMonster = true
end

-- 创建敌方小兵
function LBlockMiniGameObjsCtrl:CreateEnemyObj(dt)
    if not self._isStartSpawnEnemyMonster then
        return
    end

    -- local num = 0
    -- for k, v in pairs(self._enemyObjs) do
