                -- else
                --     if minTab.leftTime < v.leftTime then
                --         minTab = v
                --     end
                -- end


                local obj = LBlockMiniGameObj:New(self)
                obj:Init(parent, v.monsterRefId, side, objType)
                self._enemyObjs[obj:GetKey()] = obj
                v.leftTime = v.totalTime
            end
        end
    end

    -- if minTab then
    --     local obj = LBlockMiniGameObj:New(self)
    --     obj:Init(parent, minTab.monsterRefId, side, objType)
    --     self._enemyObjs[obj:GetKey()] = obj
    --     minTab.leftTime = minTab.totalTime
    --     self._createLastTime = 0
    -- end

end

-- 生产我方小兵
function LBlockMiniGameObjsCtrl:SpawnSelfObjs(dpList)
    for _, v in ipairs(dpList) do
        local monsterRefId = v.monsterRefId
        local lineNum = v.lineNum
        local obj = LBlockMiniGameObj:New(self)
        obj:InitSelf(v.dp, monsterRefId, lineNum)
        self._selfObjs[obj:GetKey()] = obj
    end
end

-- update
function LBlockMiniGameObjsCtrl:Update(dt)
    for i, obj in pairs(self._selfObjs) do
        obj:Update(dt)
    end

    self:CreateEnemyObj(dt)
    for i, obj in pairs(self._enemyObjs) do
        obj:Update(dt)
    end

    if self._updateIndex == 1 then
        self._updateIndex = 2
        self:CheckInAtkRange(self._enemyObjs, self._selfObjs)
    elseif self._updateIndex == 2 then
        self._updateIndex = 0
        self:CheckInAtkRange(self._selfObjs, self._enemyObjs)
    else
        self._updateIndex = 1
    end

    self:CheckInitMove()
end

-- 暂停游戏
function LBlockMiniGameObjsCtrl:OnPauseGame()
    for i, obj in pairs(self._selfObjs) do
        obj:OnPauseGame()
    end

    for i, obj in pairs(self._enemyObjs) do
        obj:OnPauseGame()
    end
end

-- 恢复游戏
function LBlockMiniGameObjsCtrl:OnResumeGame()
    for i, obj in pairs(self._selfObjs) do
        obj:OnResumeGame()
    end

    for i, obj in pairs(self._enemyObjs) do
        obj:OnResumeGame()
    end
end

-- 游戏结束
function LBlockMiniGameObjsCtrl:OnGameOver()
    for i, obj in pairs(self._selfObjs) do
        if obj:IsValid() then
            obj:OnPauseGame()
            obj:GetAniActor():PlayIdle()
            obj:GetMoveActor():StopMove()
        end
    end

    for i, obj in pairs(self._enemyObjs) do
        if obj:IsValid() then
            obj:OnPauseGame()
            obj:GetAniActor():PlayIdle()
            obj:GetMoveActor():StopMove()
        end
    end
end

-- region 战斗相关----------------------------------------------------

-- 检查是否有进入攻击获围
function LBlockMiniGameObjsCtrl:CheckInAtkRange(checkObjs, otherObjs)
    for i, obj in pairs(checkObjs) do
        if obj:IsValid() then
            if not obj:GetAtkActor():IsAttacking() then
                local canAtkList = {}
                for i, otherObj in pairs(otherObjs) do
                    if otherObj:IsValid() and obj:InAttackRange(otherObj) then
                        table.insert(canAtkList, otherObj)
                    end
                end

                obj:SetInAttackRangeObjs(canAtkList)
            end
        end
    end
end

-- 返回nil, 表示对象无效
function LBlockMiniGameObjsCtrl:GetObjByKey(key)
    local ojb = self._selfObjs[key] or self._enemyObjs[key]
    if not ojb then
        return nil
    end
    return ojb
end

-- 判断我方右边是否有敌方怪物
function LBlockMiniGameObjsCtrl:HadRightEnemyMonster(selfObj)
    local selfPos = selfObj:GetDpObject():GetPos()
    for _, obj in pairs(self._enemyObjs) do
        if obj:IsValid() and not obj:IsTower() then
            local pos = obj:GetDpObject():GetPos()
            if pos.x > selfPos.x and math.abs(pos.y - selfPos.y) < 1 then
                return true
            end
        end
    end
    return false
end

-- 将我方初始往右移的，改成往左移
function LBlockMiniGameObjsCtrl:CheckInitMove()
    local list = {}
    for i, obj in pairs(self._selfObjs) do
        if obj:IsValid() and not obj:IsTower() and not obj:IsJumping() then
            if obj:GetMoveActor():NeedInitMove() then
                table.insert(list, obj)
            end
        end
    end

    for _, obj in ipairs(list) do
        if not obj:GetAtkActor():IsAttacking() and not self:HadRightEnemyMonster(obj) then
            obj:GetMoveActor():ReadyInitMove()
        end
    end
end

-- endregion 战斗相关-----------------------------------------------
return LBlockMiniGameObjsCtrl
